import React, { useEffect } from "react";
import {
  Leaf,
  Award,
  Cpu,
  Heart,
  Star,
  Cookie,
  CheckCircle2,
} from "lucide-react";
import "./AboutUs2.css";
import { useNavigate } from "react-router-dom";
import { useTranslation } from "react-i18next";

const Hero = () => {
  const navigate = useNavigate();
  const { t } = useTranslation();

  return (
    <section className="hero-section">
      <div className="aboutus-container">
        <div className="hero-grid">
          <div className="hero-text">
            <div className="badge">
              <Star size={16} className="text-gold" fill="currentColor" />
              <span>{t("about_hero_badge")}</span>
            </div>

            <h1 className="hero-title">
              {t("about_hero_title")} <br />
              <span className="hero-title-highlight">
                {t("about_hero_highlight")}
              </span>
            </h1>

            <p className="hero-description">{t("about_hero_desc")}</p>

            <div className="hero-buttons">
              <button
                className="btn btn-primary btn-lg"
                onClick={() => navigate("/Products")}
              >
                <Cookie size={20} />
                <span className="taste">{t("about_hero_btn")}</span>
              </button>
            </div>

            <div className="hero-stats">
              <div className="stat-item">
                <p className="stat-value">15 +</p>
                <p className="stat-label">{t("about_stat_items")}</p>
              </div>
              <div className="stat-divider"></div>
              <div className="stat-item">
                <p className="stat-value">100 %</p>
                <p className="stat-label">{t("about_stat_quality")}</p>
              </div>
            </div>
          </div>

          <div className="hero-image-wrapper">
            <div className="hero-img-container">
              <img
                src="/images/Huggy.webp"
                alt="Biscoza Product"
                className="hero-main-img"
              />
              <div className="floating-card card-bottom">
                <div className="card-header">
                  <div className="icon-circle">
                    <CheckCircle2 size={15} color="#dd2727" />
                  </div>
                  <span className="card-text">
                    {t("about_taste_unresistable")}
                  </span>
                </div>
                <div
                  className="progress-bar"
                  style={{
                    height: "4px",
                    background: "red",
                    borderRadius: "10px",
                  }}
                ></div>
              </div>
              <div className="floating-card card-top">
                <span className="emoji">😋</span>
              </div>
            </div>
          </div>
        </div>
      </div>
    </section>
  );
};

const StorySection = () => {
  const { t } = useTranslation();
  return (
    <section className="story-section">
      <div className="aboutus-container">
        <div className="story-grid">
          <div className="story-content">
            <div className="title-wrapper" style={{ position: "relative" }}>
              <h2 className="section-title">{t("about_story_title")}</h2>
              <div className="title-decoration"></div>
            </div>
            <div className="story-text">
              <p className="story-intro">{t("about_story_text1")}</p>
              <p style={{ lineHeight: "1.8" }}>{t("about_story_text2")}</p>
            </div>
          </div>
          <div className="story-image-group">
            <div className="story-img-container">
              <img
                src="/images/dishleft.webp"
                alt="Our Story"
                style={{ width: "100%", height: "100%", objectFit: "cover" }}
              />
              <div className="story-badge">
                <span>{t("footer_rights")} 2023</span>
              </div>
            </div>
          </div>
        </div>
      </div>
    </section>
  );
};

const QuoteSection = () => {
  const { t } = useTranslation();
  return (
    <section className="quote-section">
      <div className="aboutus-container">
        <h2 className="quote-text">"{t("about_quote")}"</h2>
        <div
          style={{
            width: "60px",
            height: "4px",
            background: "white",
            margin: "20px auto",
            borderRadius: "10px",
          }}
        ></div>
      </div>
    </section>
  );
};

const QualitySection = () => {
  const { t } = useTranslation();
  const FEATURES_DATA = [
    {
      title: t("about_feat1_title"),
      description: t("about_feat1_desc"),
      icon: <Leaf />,
    },
    {
      title: t("about_feat2_title"),
      description: t("about_feat2_desc"),
      icon: <Cpu />,
    },
    {
      title: t("about_feat3_title"),
      description: t("about_feat3_desc"),
      icon: <Award />,
    },
    {
      title: t("about_feat4_title"),
      description: t("about_feat4_desc"),
      icon: <Heart />,
    },
  ];

  return (
    <section className="quality-section">
      <div className="aboutus-container">
        <div style={{ textAlign: "center", marginBottom: "3rem" }}>
          <h2 className="section-title" style={{ color: "#111827" }}>
            {t("about_quality_title")}{" "}
            <span style={{ color: "#dd2727" }}>
              {t("about_quality_highlight")}
            </span>
          </h2>
          <p style={{ maxWidth: "700px", margin: "1rem auto" }}>
            {t("about_quality_desc")}
          </p>
        </div>
        <div className="features-grid">
          {FEATURES_DATA.map((feature, index) => (
            <div key={index} className="feature-card">
              <div className="feature-icon-wrapper">{feature.icon}</div>
              <h3
                className="feature-title"
                style={{ fontSize: "1.25rem", marginBottom: "0.5rem" }}
              >
                {feature.title}
              </h3>
              <p
                className="feature-desc"
                style={{ fontSize: "0.9rem", color: "#4b5563" }}
              >
                {feature.description}
              </p>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
};

export default function AboutUs() {
  const { i18n } = useTranslation();

  // تحديث اتجاه الصفحة (dir) تلقائياً عند تغيير اللغة
  useEffect(() => {
    const currentLang = i18n.language || "ar";
    document.documentElement.dir = currentLang === "ar" ? "rtl" : "ltr";
    document.documentElement.lang = currentLang;
  }, [i18n.language]);

  return (
    <div className="app-root">
      <Hero />
      <StorySection />
      <QuoteSection />
      <QualitySection />
    </div>
  );
}
